#include<bits/stdc++.h>
using namespace std;
int x[1010],y[1010];
long long dist(int i,int j)
{
    return (1ll*(x[i]-x[j])*(x[i]-x[j])+1ll*(y[i]-y[j])*(y[i]-y[j]));
}
struct node
{
    int a,b;
    bool operator<(const node&c)const
    {
        return dist(a,b)<dist(c.a,c.b);
    }
}a[1000010];
int fa[1000010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
int main()
{
    int n,k;
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&x[i],&y[i]);
    }
    int tot=0;
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
        for(int j=i+1;j<=n;j++)
        {
            a[++tot].a=i;
            a[tot].b=j;
        }
    }
    sort(a+1,a+1+tot);
    int cnt=n;
    for(int i=1;i<=tot;i++)
    {
        if(find(a[i].a)!=find(a[i].b))
        {
            merge(a[i].a,a[i].b);
            cnt--;
            if(cnt==k-1)
            {
                printf("%.2lf",sqrt(dist(a[i].a,a[i].b)));
                return 0;
            }
        }
    }
    return 0;
}
